// Sensors
instance PositionSensor : DTDFVocab:SensingComponent [
    base:desc "Collects position data of the gantry crane's linear actuators"
    DTDFVocab:producedData CraneTelemetryTransmitted
]

instance VelocitySensor : DTDFVocab:SensingComponent [
    base:desc "Measures velocity of the gantry crane's movement"
    DTDFVocab:producedData CraneTelemetryTransmitted
]

instance ForceSensor : DTDFVocab:SensingComponent [
    base:desc "Records actuator forces applied during crane operation"
    DTDFVocab:producedData CraneTelemetryTransmitted
]

// Data transmission
instance CraneTelemetryTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom PositionSensor, VelocitySensor, ForceSensor
]

// Data stored in database
instance CraneTelemetryData : DTDFVocab:Data [
    base:desc "Persisted raw telemetry (position, velocity, force) in TimescaleDB"
    DTDFVocab:inputTo TimescaleDBEnabler
    DTDFVocab:fromData CraneTelemetryTransmitted
]

instance ControlTrajectoryData : DTDFVocab:Data [
    base:desc "Optimized control trajectories generated by the kinematic model"
    DTDFVocab:inputTo TimescaleDBEnabler
    DTDFVocab:fromData CraneTelemetryTransmitted
]

// Enablers
instance TimescaleDBEnabler : DTDFVocab:Enabler [
    base:desc "Publicly available TimescaleDB storing telemetry via PostgreSQL over local network"
    DTDFVocab:enables DataLoggingService, MonitoringService
]

instance KinematicEngineEnabler : DTDFVocab:Enabler [
    base:desc "Python-based kinematic engine performing forward kinematics"
    DTDFVocab:enables ControlTrajectoryService, ValidationService
]

// Models
instance CADKinematicModel : DTDFVocab:Model [
    base:desc "CAD-modeled kinematic chain of the gantry crane with multiple translation axes"
    DTDFVocab:inputTo KinematicEngineEnabler
]

// Services
instance MonitoringService : DTDFVocab:Service [
    base:desc "Real‑time monitoring of actuator positions and forces"
    DTDFVocab:provides PositionInsight, ForceInsight
]

instance ControlTrajectoryService : DTDFVocab:Service [
    base:desc "Generates optimal control trajectories from the CAD kinematic model"
    DTDFVocab:provides ControlTrajectoryInsight, GenerateOptimalControlAction
]

instance DataLoggingService : DTDFVocab:Service [
    base:desc "Comprehensive historical data logging of all operational states"
    DTDFVocab:provides HistoricalDataInsight
]

instance VisualizationService : DTDFVocab:Service [
    base:desc "3‑D visualization of crane motion, consumed by Grafana dashboard"
    DTDFVocab:provides VisualizationInsight
]

instance ValidationService : DTDFVocab:Service [
    base:desc "Continuous validation comparing live measurements against simulated predictions"
    DTDFVocab:provides ValidationInsight
]

// Insights
instance PositionInsight : DTDFVocab:Insight [
    base:desc "Current position of the gantry crane actuators"
]

instance ForceInsight : DTDFVocab:Insight [
    base:desc "Current actuator forces during crane operation"
]

instance ControlTrajectoryInsight : DTDFVocab:Insight [
    base:desc "Optimized control trajectories for the gantry crane"
]

instance HistoricalDataInsight : DTDFVocab:Insight [
    base:desc "Historical telemetry of the gantry crane for trend analysis"
]

instance VisualizationInsight : DTDFVocab:Insight [
    base:desc "Real‑time 3‑D visualization of crane motion"
]

instance ValidationInsight : DTDFVocab:Insight [
    base:desc "Results of live vs. simulated validation checks"
]

// Actions
instance GenerateOptimalControlAction : DTDFVocab:Action [
    base:desc "Automatically generates optimum control commands for the gantry crane"
    DTDFVocab:IsAutomatic true
]

// Environment
instance LabEnvironment : DTDFVocab:Environment [
    base:contains PositionSensor, VelocitySensor, ForceSensor, CADKinematicModel,
    TimescaleDBEnabler, KinematicEngineEnabler,
    MonitoringService, ControlTrajectoryService, DataLoggingService, VisualizationService,
    ValidationService
]

